{
  "name": "OmegleClone",
  "description": "A real-time text chat application that pairs users based on shared interests and gender preferences using Socket.io."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Gender = 'Male' | 'Female' | 'Other';

export interface UserPreferences {
  displayName: string;
  age: number;
  gender: Gender;
  interests: string[];
  preferredGender: Gender | 'Any';
}

export interface Message {
  id: string;
  sender: 'me' | 'stranger' | 'system';
  text: string;
  timestamp: number;
}

export interface PartnerData {
  socketId: string;
  displayName?: string;
  interests: string[];
  age?: number;
  gender?: string;
}

export type ChatState = 'landing' | 'searching' | 'chatting';

// In a production app, this would be an environment variable
// For local development as requested by the user, we assume localhost:3000
export const SOCKET_URL = 'http://localhost:3000';

export const SYSTEM_NAME = 'System';

import { io, Socket } from 'socket.io-client';
import { SOCKET_URL } from '../constants';

// Create a singleton socket instance
// autoConnect is false so we can control when to connect (e.g. after user info is set)
export const socket: Socket = io(SOCKET_URL, {
  autoConnect: false,
  reconnectionAttempts: 5,
  transports: ['websocket', 'polling'], // Fallback options
});

export const connectSocket = () => {
  if (!socket.connected) {
    socket.connect();
  }
};

export const disconnectSocket = () => {
  if (socket.connected) {
    socket.disconnect();
  }
};

import React from 'react';
import { Ghost, Wifi, WifiOff } from 'lucide-react';

interface HeaderProps {
  isConnected: boolean;
  onlineCount?: number;
}

export const Header: React.FC<HeaderProps> = ({ isConnected, onlineCount }) => {
  return (
    <header className="h-16 border-b border-slate-800 bg-slate-900/50 backdrop-blur-md flex items-center justify-between px-4 sm:px-6 fixed top-0 w-full z-10">
      <div className="flex items-center gap-2">
        <div className="bg-gradient-to-tr from-primary to-accent p-2 rounded-lg shadow-lg shadow-primary/20">
          <Ghost className="w-6 h-6 text-white" />
        </div>
        <h1 className="text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
          OmegleClone
        </h1>
      </div>

      <div className="flex items-center gap-4">
        {onlineCount !== undefined && (
           <span className="text-xs text-slate-400 hidden sm:inline-block">
            {onlineCount} users online
          </span>
        )}
        <div className={`flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium border ${
          isConnected 
            ? 'bg-green-500/10 text-green-400 border-green-500/20' 
            : 'bg-red-500/10 text-red-400 border-red-500/20'
        }`}>
          {isConnected ? <Wifi className="w-3.5 h-3.5" /> : <WifiOff className="w-3.5 h-3.5" />}
          <span className="hidden xs:inline">{isConnected ? 'Connected' : 'Offline'}</span>
        </div>
      </div>
    </header>
  );
};

import React, { useState } from 'react';
import { UserPreferences, Gender } from '../types';
import { MessageSquare, Plus, X, Sparkles } from 'lucide-react';

interface LandingProps {
  onStart: (prefs: UserPreferences) => void;
  isConnecting: boolean;
}

export const Landing: React.FC<LandingProps> = ({ onStart, isConnecting }) => {
  const [displayName, setDisplayName] = useState('');
  const [age, setAge] = useState<string>('');
  const [gender, setGender] = useState<Gender>('Male');
  const [preferredGender, setPreferredGender] = useState<Gender | 'Any'>('Any');
  const [interestInput, setInterestInput] = useState('');
  const [interests, setInterests] = useState<string[]>([]);

  const handleAddInterest = (e?: React.FormEvent) => {
    e?.preventDefault();
    const trimmed = interestInput.trim();
    if (trimmed && !interests.includes(trimmed)) {
      setInterests([...interests, trimmed]);
      setInterestInput('');
    }
  };

  const removeInterest = (tag: string) => {
    setInterests(interests.filter(i => i !== tag));
  };

  const handleStart = () => {
    const ageNum = parseInt(age);
    if (!age || isNaN(ageNum) || ageNum < 18) {
      alert("You must be 18+ to use this app.");
      return;
    }

    onStart({
      displayName: displayName.trim() || 'Stranger',
      age: ageNum,
      gender,
      preferredGender,
      interests
    });
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen pt-16 pb-6 px-4">
      <div className="w-full max-w-lg bg-slate-800/50 border border-slate-700 p-6 sm:p-8 rounded-2xl shadow-2xl backdrop-blur-sm">

        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-full bg-slate-700/50 mb-4 ring-1 ring-slate-600">
             <Sparkles className="w-8 h-8 text-primary" />
          </div>
          <h2 className="text-2xl sm:text-3xl font-bold text-white mb-2">Find a Chat Partner</h2>
          <p className="text-slate-400">Match based on interests, age, and vibes.</p>
        </div>

        <div className="space-y-6">
          {/* Display Name */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300">Display Name (Optional)</label>
            <input
              type="text"
              value={displayName}
              onChange={(e) => setDisplayName(e.target.value)}
              placeholder="Anonymous"
              className="w-full bg-slate-900/50 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            {/* Age */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-300">Age</label>
              <input
                type="number"
                value={age}
                onChange={(e) => setAge(e.target.value)}
                placeholder="18"
                min="18"
                max="99"
                className="w-full bg-slate-900/50 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
              />
            </div>

            {/* Gender */}
            <div className="space-y-2">
              <label className="text-sm font-medium text-slate-300">Your Gender</label>
              <select
                value={gender}
                onChange={(e) => setGender(e.target.value as Gender)}
                className="w-full bg-slate-900/50 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all appearance-none"
              >
                <option value="Male">Male</option>
                <option value="Female">Female</option>
                <option value="Other">Other</option>
              </select>
            </div>
          </div>

          {/* Preferred Gender */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300">Looking For</label>
            <select
                value={preferredGender}
                onChange={(e) => setPreferredGender(e.target.value as Gender | 'Any')}
                className="w-full bg-slate-900/50 border border-slate-700 rounded-lg px-4 py-2.5 text-white focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all appearance-none"
              >
                <option value="Any">Anyone</option>
                <option value="Male">Male</option>
                <option value="Female">Female</option>
                <option value="Other">Other</option>
              </select>
          </div>

          {/* Interests */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-slate-300">Interests (Press Enter)</label>
            <div className="relative">
              <input
                type="text"
                value={interestInput}
                onChange={(e) => setInterestInput(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAddInterest(e)}
                placeholder="coding, music, anime..."
                className="w-full bg-slate-900/50 border border-slate-700 rounded-lg pl-4 pr-10 py-2.5 text-white focus:ring-2 focus:ring-primary focus:border-transparent outline-none transition-all"
              />
              <button 
                onClick={() => handleAddInterest()}
                className="absolute right-2 top-1/2 -translate-y-1/2 p-1 hover:bg-slate-700 rounded-md transition-colors"
              >
                <Plus className="w-4 h-4 text-slate-400" />
              </button>
            </div>

            <div className="flex flex-wrap gap-2 mt-3 min-h-[32px]">
              {interests.map((interest) => (
                <span key={interest} className="inline-flex items-center gap-1 bg-slate-700/50 text-slate-200 text-sm px-2.5 py-1 rounded-full border border-slate-600">
                  {interest}
                  <button onClick={() => removeInterest(interest)} className="hover:text-white">
                    <X className="w-3 h-3" />
                  </button>
                </span>
              ))}
              {interests.length === 0 && (
                <span className="text-xs text-slate-500 italic">No interests added yet.</span>
              )}
            </div>
          </div>

          <button
            onClick={handleStart}
            disabled={isConnecting}
            className="w-full bg-gradient-to-r from-primary to-accent hover:opacity-90 disabled:opacity-50 disabled:cursor-not-allowed text-white font-semibold py-3.5 rounded-xl shadow-lg shadow-primary/25 transition-all transform active:scale-[0.98] flex items-center justify-center gap-2"
          >
            {isConnecting ? (
              <>
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />
                Connecting...
              </>
            ) : (
              <>
                <MessageSquare className="w-5 h-5" />
                Start Chatting
              </>
            )}
          </button>

        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Message, PartnerData } from '../types';
import { Send, LogOut, SkipForward, AlertCircle } from 'lucide-react';

interface ChatRoomProps {
  partner: PartnerData;
  messages: Message[];
  onSendMessage: (text: string) => void;
  onNext: () => void;
  onStop: () => void;
  isPartnerDisconnected: boolean;
}

export const ChatRoom: React.FC<ChatRoomProps> = ({ 
  partner, 
  messages, 
  onSendMessage, 
  onNext, 
  onStop,
  isPartnerDisconnected
}) => {
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputText.trim() || isPartnerDisconnected) return;
    onSendMessage(inputText.trim());
    setInputText('');
  };

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] mt-16 max-w-5xl mx-auto w-full bg-slate-900 sm:border-x border-slate-800">
      {/* Chat Header / Info Bar */}
      <div className="flex items-center justify-between px-4 py-3 bg-slate-800/80 backdrop-blur-sm border-b border-slate-700 z-10 sticky top-0">
        <div className="flex flex-col">
           <div className="flex items-center gap-2">
            <span className={`w-2.5 h-2.5 rounded-full ${isPartnerDisconnected ? 'bg-red-500' : 'bg-green-500 animate-pulse'}`} />
            <h3 className="font-semibold text-white">
              {isPartnerDisconnected ? 'Stranger (Disconnected)' : (partner.displayName || 'Stranger')}
            </h3>
           </div>
           {partner.interests.length > 0 && (
             <p className="text-xs text-slate-400 mt-0.5 truncate max-w-[200px] sm:max-w-md">
               Interests: {partner.interests.join(', ')}
             </p>
           )}
        </div>

        <div className="flex items-center gap-2">
          <button 
            onClick={onStop}
            className="p-2 text-slate-400 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-colors"
            title="Stop Chat"
          >
            <LogOut className="w-5 h-5" />
          </button>
          <button 
            onClick={onNext}
            className="flex items-center gap-2 px-4 py-2 bg-slate-700 hover:bg-slate-600 text-white rounded-lg text-sm font-medium transition-colors"
          >
            <span className="hidden sm:inline">Next</span>
            <SkipForward className="w-4 h-4" />
          </button>
        </div>
      </div>

      {/* Messages Area */}
      <div className="flex-1 overflow-y-auto p-4 space-y-4 scrollbar-thin scrollbar-thumb-slate-700 scrollbar-track-transparent">
        {/* Welcome System Message */}
        <div className="flex justify-center my-4">
          <div className="bg-slate-800/50 text-slate-400 text-xs px-3 py-1.5 rounded-full border border-slate-700">
            You are now chatting with a random stranger. Say Hi!
          </div>
        </div>

        {messages.map((msg) => {
           const isSystem = msg.sender === 'system';
           const isMe = msg.sender === 'me';

           if (isSystem) {
             return (
               <div key={msg.id} className="flex justify-center my-2">
                  <span className="text-xs text-slate-500 italic flex items-center gap-1.5">
                    <AlertCircle className="w-3 h-3" />
                    {msg.text}
                  </span>
               </div>
             );
           }

           return (
            <div 
              key={msg.id} 
              className={`flex w-full ${isMe ? 'justify-end' : 'justify-start'}`}
            >
              <div 
                className={`max-w-[85%] sm:max-w-[70%] px-4 py-2.5 rounded-2xl text-sm leading-relaxed shadow-sm ${
                  isMe 
                    ? 'bg-chat-user text-white rounded-tr-none' 
                    : 'bg-chat-stranger text-slate-100 rounded-tl-none'
                }`}
              >
                {msg.text}
                <div className={`text-[10px] mt-1 opacity-70 ${isMe ? 'text-blue-100' : 'text-slate-400'}`}>
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
           );
        })}

        {isPartnerDisconnected && (
          <div className="flex flex-col items-center justify-center gap-3 py-8 opacity-75">
             <p className="text-slate-400">The stranger has disconnected.</p>
             <button 
               onClick={onNext}
               className="bg-primary hover:bg-blue-600 text-white px-6 py-2 rounded-full font-medium transition-colors shadow-lg shadow-blue-500/20"
             >
               Find New Partner
             </button>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input Area */}
      <div className="p-4 bg-slate-900 border-t border-slate-800">
        <form onSubmit={handleSend} className="relative flex items-center gap-2 max-w-4xl mx-auto">
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            disabled={isPartnerDisconnected}
            placeholder={isPartnerDisconnected ? "Partner disconnected..." : "Type your message..."}
            className="w-full bg-slate-800 border border-slate-700 text-white placeholder-slate-500 rounded-xl pl-4 pr-12 py-3 focus:ring-2 focus:ring-primary focus:border-transparent outline-none disabled:opacity-50 disabled:cursor-not-allowed transition-all"
          />
          <button
            type="submit"
            disabled={!inputText.trim() || isPartnerDisconnected}
            className="absolute right-2 p-2 bg-primary text-white rounded-lg hover:bg-blue-600 disabled:opacity-0 disabled:scale-75 transition-all"
          >
            <Send className="w-4 h-4" />
          </button>
        </form>
      </div>
    </div>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { Header } from './components/Header';
import { Landing } from './components/Landing';
import { ChatRoom } from './components/ChatRoom';
import { socket, connectSocket, disconnectSocket } from './services/socket';
import { UserPreferences, ChatState, Message, PartnerData } from './types';
import { Loader2 } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

function App() {
  const [appState, setAppState] = useState<ChatState>('landing');
  const [isConnected, setIsConnected] = useState(socket.connected);
  const [messages, setMessages] = useState<Message[]>([]);
  const [partner, setPartner] = useState<PartnerData | null>(null);
  const [onlineCount, setOnlineCount] = useState(0);
  const [isPartnerDisconnected, setIsPartnerDisconnected] = useState(false);
  const userPreferences = useRef<UserPreferences | null>(null);

  useEffect(() => {
    // Socket Event Listeners
    const onConnect = () => {
      setIsConnected(true);
      console.log('Connected to server');
    };

    const onDisconnect = () => {
      setIsConnected(false);
      console.log('Disconnected from server');
    };

    const onPartnerFound = (data: PartnerData) => {
      setPartner(data);
      setAppState('chatting');
      setMessages([]);
      setIsPartnerDisconnected(false);
    };

    const onMessage = (data: { text: string, senderId: string }) => {
      setMessages(prev => [
        ...prev, 
        { 
          id: uuidv4(), 
          text: data.text, 
          sender: 'stranger', 
          timestamp: Date.now() 
        }
      ]);
    };

    const onPartnerDisconnected = () => {
      setIsPartnerDisconnected(true);
      setMessages(prev => [
        ...prev,
        {
          id: uuidv4(),
          text: 'Stranger has left the chat.',
          sender: 'system',
          timestamp: Date.now()
        }
      ]);
    };

    const onStats = (data: { usersOnline: number }) => {
      setOnlineCount(data.usersOnline);
    };

    socket.on('connect', onConnect);
    socket.on('disconnect', onDisconnect);
    socket.on('partner_found', onPartnerFound);
    socket.on('message', onMessage);
    socket.on('partner_disconnected', onPartnerDisconnected);
    socket.on('stats', onStats);

    return () => {
      socket.off('connect', onConnect);
      socket.off('disconnect', onDisconnect);
      socket.off('partner_found', onPartnerFound);
      socket.off('message', onMessage);
      socket.off('partner_disconnected', onPartnerDisconnected);
      socket.off('stats', onStats);
    };
  }, []);

  const handleStartSearch = (prefs: UserPreferences) => {
    userPreferences.current = prefs;
    connectSocket();

    // If socket is already connected, emit immediately
    if (socket.connected) {
      socket.emit('find_partner', prefs);
      setAppState('searching');
    } else {
      // Wait for connection then emit
      setAppState('searching');
      socket.once('connect', () => {
        socket.emit('find_partner', prefs);
      });
    }
  };

  const handleSendMessage = (text: string) => {
    if (!text.trim()) return;

    socket.emit('send_message', { text });
    setMessages(prev => [
      ...prev,
      {
        id: uuidv4(),
        text: text,
        sender: 'me',
        timestamp: Date.now()
      }
    ]);
  };

  const handleNext = () => {
    // Disconnect current chat but stay connected to server to find new partner
    socket.emit('skip_chat');
    setPartner(null);
    setMessages([]);
    setIsPartnerDisconnected(false);
    setAppState('searching');

    // Re-emit find_partner with stored preferences
    if (userPreferences.current) {
      socket.emit('find_partner', userPreferences.current);
    } else {
      setAppState('landing');
    }
  };

  const handleStop = () => {
    socket.emit('leave_chat');
    disconnectSocket();
    setAppState('landing');
    setPartner(null);
    setMessages([]);
    setIsPartnerDisconnected(false);
  };

  return (
    <div className="min-h-screen bg-slate-950 font-sans selection:bg-primary/30 selection:text-white">
      <Header isConnected={isConnected} onlineCount={onlineCount} />

      {appState === 'landing' && (
        <Landing 
          onStart={handleStartSearch} 
          isConnecting={appState === 'searching'} 
        />
      )}

      {appState === 'searching' && (
        <div className="flex flex-col items-center justify-center min-h-screen text-center px-4">
           <div className="relative">
             <div className="absolute inset-0 bg-primary/20 blur-xl rounded-full animate-pulse"></div>
             <Loader2 className="w-16 h-16 text-primary animate-spin relative z-10" />
           </div>
           <h2 className="text-2xl font-semibold text-white mt-8 mb-2">Looking for a match...</h2>
           <p className="text-slate-400 max-w-md">
             Scanning for users with interests: <span className="text-slate-200">{userPreferences.current?.interests.join(', ') || 'Any'}</span>
           </p>
           <button 
             onClick={() => {
                socket.emit('leave_chat'); // Cancel search
                setAppState('landing');
             }}
             className="mt-8 px-6 py-2 border border-slate-700 hover:bg-slate-800 rounded-full text-slate-300 transition-colors"
           >
             Cancel
           </button>
        </div>
      )}

      {appState === 'chatting' && partner && (
        <ChatRoom
          partner={partner}
          messages={messages}
          onSendMessage={handleSendMessage}
          onNext={handleNext}
          onStop={handleStop}
          isPartnerDisconnected={isPartnerDisconnected}
        />
      )}
    </div>
  );
}

export default App;

import express from 'express';
import { createServer } from 'http';
import { Server } from 'socket.io';
import cors from 'cors';
import { v4 as uuidv4 } from 'uuid';

const app = express();
app.use(cors());

const httpServer = createServer(app);
const io = new Server(httpServer, {
  cors: {
    origin: "*", // Allow all origins for dev simplicity
    methods: ["GET", "POST"]
  }
});

const PORT = process.env.PORT || 3000;

// Data Structures
// Users mapped by socket ID
const users = new Map();
// Waiting users queue
const waitingQueue = []; 

// Helper to remove user from queue
const removeFromQueue = (socketId) => {
  const index = waitingQueue.findIndex(u => u.socketId === socketId);
  if (index !== -1) {
    waitingQueue.splice(index, 1);
  }
};

const findMatch = (user) => {
  // Filter queue for eligible candidates
  // 1. Candidate must not be the user themselves
  // 2. Candidate's gender must match user's preference
  // 3. User's gender must match candidate's preference

  const candidates = waitingQueue.filter(candidate => {
    if (candidate.socketId === user.socketId) return false;

    // Check User's preference
    if (user.preferredGender !== 'Any' && candidate.gender !== user.preferredGender) return false;

    // Check Candidate's preference
    if (candidate.preferredGender !== 'Any' && user.gender !== candidate.preferredGender) return false;

    return true;
  });

  if (candidates.length === 0) return null;

  // Score candidates based on interests
  let bestMatch = null;
  let maxScore = -1;

  for (const candidate of candidates) {
    let score = 0;
    // Calculate interest overlap
    const userInterests = new Set(user.interests.map(i => i.toLowerCase()));
    const candidateInterests = new Set(candidate.interests.map(i => i.toLowerCase()));

    for (const interest of userInterests) {
      if (candidateInterests.has(interest)) {
        score++;
      }
    }

    if (score > maxScore) {
      maxScore = score;
      bestMatch = candidate;
    }
  }

  // If no interests match (score 0), we still return the 'bestMatch' (which is just the first one or random)
  // because we filtered for gender already. 
  // If we wanted to enforce interest matching strictly, we would check if maxScore > 0.

  return bestMatch;
};

io.on('connection', (socket) => {
  console.log(`User connected: ${socket.id}`);

  // Store basic connection info, but not ready to chat yet
  users.set(socket.id, {
    socketId: socket.id,
    status: 'idle'
  });

  // Emit stats to everyone
  io.emit('stats', { usersOnline: users.size });

  socket.on('find_partner', (data) => {
    const user = {
      ...data,
      socketId: socket.id,
      status: 'waiting',
      currentRoom: null
    };
    users.set(socket.id, user);

    console.log(`User ${user.displayName} (${user.gender}) looking for ${user.preferredGender} with interests: ${user.interests}`);

    // Try to match immediately
    const match = findMatch(user);

    if (match) {
      // Match found!
      console.log(`Match found: ${user.displayName} <-> ${match.displayName}`);

      // Remove match from queue
      removeFromQueue(match.socketId);

      // Create room
      const roomId = uuidv4();
      user.currentRoom = roomId;
      match.currentRoom = roomId;
      user.status = 'chatting';
      match.status = 'chatting';

      // Update users map
      users.set(user.socketId, user);
      users.set(match.socketId, match);

      // Join sockets
      socket.join(roomId);
      io.sockets.sockets.get(match.socketId)?.join(roomId);

      // Notify both
      socket.emit('partner_found', { 
        socketId: match.socketId,
        displayName: match.displayName,
        interests: match.interests,
        gender: match.gender
      });

      io.to(match.socketId).emit('partner_found', {
        socketId: user.socketId,
        displayName: user.displayName,
        interests: user.interests,
        gender: user.gender
      });

    } else {
      // No match yet, add to queue
      waitingQueue.push(user);
      console.log(`User ${user.displayName} added to waiting queue.`);
    }
  });

  socket.on('send_message', (data) => {
    const user = users.get(socket.id);
    if (user && user.currentRoom) {
      // Broadcast to room excluding sender
      socket.to(user.currentRoom).emit('message', {
        text: data.text,
        senderId: socket.id
      });
    }
  });

  const handleDisconnectOrSkip = () => {
    const user = users.get(socket.id);
    if (!user) return;

    // Remove from queue if waiting
    removeFromQueue(socket.id);

    // If chatting, notify partner
    if (user.currentRoom) {
      socket.to(user.currentRoom).emit('partner_disconnected');

      // We don't automatically put the partner back in queue, 
      // the client will handle 'next' action.
      // But we should clean up the room reference for the other user roughly?
      // Actually, simply notifying is enough. The other user is effectively 'stranded' until they click next.

      // Clean up current user's room
      user.currentRoom = null;
      user.status = 'idle';
      socket.leave(user.currentRoom); // Actually room ID is lost here but socket.leave(null) does nothing.
    }
  };

  socket.on('skip_chat', () => {
    handleDisconnectOrSkip();
    // User is staying connected, just leaving current chat
    const user = users.get(socket.id);
    if(user) user.status = 'idle';
  });

  socket.on('leave_chat', () => {
    handleDisconnectOrSkip();
    const user = users.get(socket.id);
    if(user) user.status = 'idle';
  });

  socket.on('disconnect', () => {
    console.log(`User disconnected: ${socket.id}`);
    handleDisconnectOrSkip();
    users.delete(socket.id);
    io.emit('stats', { usersOnline: users.size });
  });
});

httpServer.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

