export const SYSTEM_NAME = 'System';

import { v4 as uuidv4 } from 'uuid';
import { UserPreferences } from '../types';

// --- TYPES ---
type EventHandler = (...args: any[]) => void;

interface SignalingMessage {
  type: 'ADVERTISE' | 'MATCH_OFFER' | 'MATCH_CONFIRM' | 'MESSAGE' | 'DISCONNECT';
  senderId: string;
  payload?: any;
}

// --- VIRTUAL SERVER LOGIC (Ported from server.js) ---
// This logic runs in every client to facilitate P2P matching via BroadcastChannel

const isCompatible = (me: any, them: any) => {
  if (me.socketId === them.socketId) return false;
  // Check My preference
  if (me.preferredGender !== 'Any' && them.gender !== me.preferredGender) return false;
  // Check Their preference
  if (them.preferredGender !== 'Any' && me.gender !== them.preferredGender) return false;
  return true;
};

const calculateScore = (userA: any, userB: any) => {
  let score = 0;
  const interestsA = new Set(userA.interests.map((i: string) => i.toLowerCase()));
  const interestsB = new Set(userB.interests.map((i: string) => i.toLowerCase()));

  for (const interest of interestsA) {
    if (interestsB.has(interest)) score++;
  }
  return score;
};

// --- VIRTUAL SOCKET CLASS ---
class VirtualSocket {
  id: string;
  connected: boolean = false;
  private listeners: Map<string, EventHandler[]> = new Map();
  private channel: BroadcastChannel;

  // State
  private user: any = null;
  private currentRoom: string | null = null;
  private state: 'idle' | 'searching' | 'chatting' = 'idle';
  private botTimeout: any = null;
  private botInterval: any = null;

  constructor() {
    this.id = uuidv4();
    this.channel = new BroadcastChannel('omegle-clone-signaling');

    // Listen for P2P messages from other tabs
    this.channel.onmessage = (event) => {
      this.handleSignalingMessage(event.data as SignalingMessage);
    };

    console.log('[VirtualSocket] Initialized in Serverless Mode');
  }

  // --- PUBLIC API (Mimics socket.io-client) ---

  connect() {
    if (!this.connected) {
      setTimeout(() => {
        this.connected = true;
        this.trigger('connect');
      }, 100);
    }
  }

  disconnect() {
    if (this.connected) {
      this.handleLeave();
      this.connected = false;
      this.trigger('disconnect');
    }
  }

  emit(event: string, data?: any) {
    console.log(`[Emit] ${event}`, data);

    switch (event) {
      case 'find_partner':
        this.handleFindPartner(data);
        break;
      case 'send_message':
        this.handleSendMessage(data);
        break;
      case 'leave_chat':
      case 'skip_chat':
        this.handleLeave();
        break;
    }
  }

  on(event: string, callback: EventHandler) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event)?.push(callback);
  }

  off(event: string, callback: EventHandler) {
    const callbacks = this.listeners.get(event);
    if (callbacks) {
      this.listeners.set(event, callbacks.filter(cb => cb !== callback));
    }
  }

  once(event: string, callback: EventHandler) {
    const onceWrapper = (...args: any[]) => {
      callback(...args);
      this.off(event, onceWrapper);
    };
    this.on(event, onceWrapper);
  }

  // --- INTERNAL LOGIC ---

  private trigger(event: string, ...args: any[]) {
    this.listeners.get(event)?.forEach(cb => cb(...args));
  }

  private broadcast(type: SignalingMessage['type'], payload?: any) {
    this.channel.postMessage({
      type,
      senderId: this.id,
      payload
    });
  }

  private handleFindPartner(prefs: UserPreferences) {
    this.user = { ...prefs, socketId: this.id };
    this.state = 'searching';

    // 1. Broadcast presence to other tabs
    this.broadcast('ADVERTISE', this.user);

    // 2. Start Bot Timer (Fallback if no real tabs match)
    this.startBotTimer();
  }

  private handleSendMessage(data: { text: string }) {
    if (this.currentRoom) {
      // If chatting with Bot
      if (this.currentRoom.startsWith('bot-')) {
        // Echo or simple response logic could go here
        return;
      }

      // If chatting with real tab
      this.broadcast('MESSAGE', {
        roomId: this.currentRoom,
        text: data.text
      });
    }
  }

  private handleLeave() {
    this.clearBotTimers();
    if (this.currentRoom && !this.currentRoom.startsWith('bot-')) {
      this.broadcast('DISCONNECT', { roomId: this.currentRoom });
    }
    this.currentRoom = null;
    this.state = 'idle';
  }

  // --- SIGNALING HANDLER (P2P Logic) ---

  private handleSignalingMessage(msg: SignalingMessage) {
    if (msg.senderId === this.id) return; // Ignore self

    switch (msg.type) {
      case 'ADVERTISE':
        this.handleAdvertise(msg.senderId, msg.payload);
        break;
      case 'MATCH_OFFER':
        this.handleMatchOffer(msg.payload);
        break;
      case 'MATCH_CONFIRM':
        this.handleMatchConfirm(msg.payload);
        break;
      case 'MESSAGE':
        if (this.currentRoom === msg.payload.roomId) {
          this.trigger('message', {
             text: msg.payload.text,
             senderId: msg.senderId
          });
        }
        break;
      case 'DISCONNECT':
        if (this.currentRoom === msg.payload.roomId) {
          this.trigger('partner_disconnected');
          this.currentRoom = null;
          this.state = 'idle';
        }
        break;
    }
  }

  // --- MATCHING LOGIC ---

  private handleAdvertise(senderId: string, remoteUser: any) {
    // If I am not searching, ignore
    if (this.state !== 'searching' || !this.user) return;

    // Check compatibility (Shared Backend Logic)
    if (isCompatible(this.user, remoteUser)) {
      const score = calculateScore(this.user, remoteUser);

      // Send Offer
      // Add random delay to prevent collision
      setTimeout(() => {
        if (this.state !== 'searching') return;
        this.broadcast('MATCH_OFFER', {
           targetId: senderId,
           offererUser: this.user,
           score
        });
      }, Math.random() * 500);
    }
  }

  private handleMatchOffer(payload: any) {
    // If I received an offer and I am still searching
    if (this.state === 'searching' && payload.targetId === this.id) {
       // Accept immediately (First come first serve for simplicity)
       const roomId = uuidv4();
       this.clearBotTimers();

       this.broadcast('MATCH_CONFIRM', {
         targetId: payload.offererUser.socketId,
         roomId,
         accepterUser: this.user
       });

       this.finalizeMatch(roomId, payload.offererUser);
    }
  }

  private handleMatchConfirm(payload: any) {
    if (this.state === 'searching' && payload.targetId === this.id) {
      this.clearBotTimers();
      this.finalizeMatch(payload.roomId, payload.accepterUser);
    }
  }

  private finalizeMatch(roomId: string, partner: any) {
    this.state = 'chatting';
    this.currentRoom = roomId;
    this.trigger('partner_found', {
      socketId: partner.socketId,
      displayName: partner.displayName,
      interests: partner.interests,
      gender: partner.gender
    });
  }

  // --- BOT SIMULATION ---

  private startBotTimer() {
    this.clearBotTimers();
    // Wait 3 seconds before matching with a bot
    this.botTimeout = setTimeout(() => {
      if (this.state === 'searching') {
        this.matchWithBot();
      }
    }, 3000);
  }

  private clearBotTimers() {
    if (this.botTimeout) clearTimeout(this.botTimeout);
    if (this.botInterval) clearInterval(this.botInterval);
  }

  private matchWithBot() {
    this.state = 'chatting';
    this.currentRoom = `bot-${uuidv4()}`;

    // Generate Bot Profile based on user's interests if possible
    const botInterests = this.user.interests.length > 0 
      ? [this.user.interests[0], 'AI', 'Technology'] 
      : ['Reading', 'Coffee', 'Mystery'];

    this.trigger('partner_found', {
      socketId: 'BOT',
      displayName: 'Stranger',
      interests: botInterests,
      gender: this.user.preferredGender === 'Any' ? 'Female' : this.user.preferredGender
    });

    // Simulate Bot Messages
    const botMessages = [
      "Hi there! How's it going?",
      "I see we have similar interests.",
      "What are you up to today?",
      "That's interesting!",
      "I'm actually a simulated bot because no other users are online in this demo.",
      "But you can open a new tab to chat with yourself via P2P!"
    ];

    let msgIndex = 0;
    this.botInterval = setInterval(() => {
      if (this.state !== 'chatting' || !this.currentRoom?.startsWith('bot-')) {
        this.clearBotTimers();
        return;
      }

      if (msgIndex < botMessages.length) {
        this.trigger('message', {
          text: botMessages[msgIndex++],
          senderId: 'BOT'
        });
      }
    }, 4000);
  }
}

