// Initialize the real Socket.IO client
export const socket: Socket = io(SOCKET_URL, {
  autoConnect: false,
  reconnectionAttempts: 5,
  transports: ['websocket', 'polling'], // Try websocket first, fall back to polling
});

export const connectSocket = () => {
  if (!socket.connected) {
    socket.connect();
  }
};

export const disconnectSocket = () => {
  if (socket.connected) {
    socket.disconnect();
  }
};

// Check localStorage first (runtime override), then environment variable (build time), then default to localhost
const LOCAL_STORAGE_KEY = 'omegle_clone_server_url';

export const getStoredSocketUrl = () => {
  if (typeof window !== 'undefined') {
    return localStorage.getItem(LOCAL_STORAGE_KEY);
  }
  return null;
};

export const setStoredSocketUrl = (url: string) => {
  if (typeof window !== 'undefined') {
    localStorage.setItem(LOCAL_STORAGE_KEY, url);
  }
};

export const resetStoredSocketUrl = () => {
  if (typeof window !== 'undefined') {
    localStorage.removeItem(LOCAL_STORAGE_KEY);
  }
};

