             <span className="text-[10px] uppercase tracking-widest text-slate-500 font-bold">In the Loom</span>
             <span className="text-sm text-indigo-200 font-mono">{onlineCount}</span>
           </div>
        )}
        <div className={`flex items-center gap-2 px-4 py-1.5 rounded-full text-xs font-bold border-2 transition-all ${
          isConnected 
            ? 'bg-emerald-500/5 text-emerald-400 border-emerald-500/20' 
            : 'bg-rose-500/5 text-rose-400 border-rose-500/20'
        }`}>
          {isConnected ? <Wifi className="w-3.5 h-3.5" /> : <WifiOff className="w-3.5 h-3.5" />}
          <span className="hidden xs:inline uppercase tracking-tight">{isConnected ? 'Threaded' : 'Unlinked'}</span>
        </div>
      </div>
    </header>
  );
};

