import React, { useState, useEffect, useRef } from 'react';
import { Message, PartnerData } from '../types';
import { Send, LogOut, SkipForward, AlertCircle, Quote } from 'lucide-react';

interface ChatRoomProps {
  partner: PartnerData;
  messages: Message[];
  onSendMessage: (text: string) => void;
  onNext: () => void;
  onStop: () => void;
  isPartnerDisconnected: boolean;
}

export const ChatRoom: React.FC<ChatRoomProps> = ({ 
  partner, 
  messages, 
  onSendMessage, 
  onNext, 
  onStop,
  isPartnerDisconnected
}) => {
  const [inputText, setInputText] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const handleSend = (e?: React.FormEvent) => {
    e?.preventDefault();
    if (!inputText.trim() || isPartnerDisconnected) return;
    onSendMessage(inputText.trim());
    setInputText('');
  };

  return (
    <div className="flex flex-col h-[calc(100vh-64px)] mt-16 max-w-5xl mx-auto w-full bg-denim-950 sm:border-x-2 border-dashed border-indigo-900/50">

      {/* Thread Info Bar */}
      <div className="flex items-center justify-between px-6 py-4 bg-denim-900/40 backdrop-blur-md border-b-2 border-dashed border-indigo-900/50 z-10 sticky top-0">
        <div className="flex items-center gap-4">
           <div className="relative">
              <div className={`w-12 h-12 rounded-2xl rotate-3 border-2 border-dashed flex items-center justify-center transition-all ${isPartnerDisconnected ? 'bg-slate-800 border-slate-700' : 'bg-indigo-600 border-indigo-400 shadow-lg shadow-indigo-600/20'}`}>
                <span className="text-xl font-black text-white">{partner.displayName?.[0]?.toUpperCase() || 'S'}</span>
              </div>
              <div className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-4 border-denim-950 ${isPartnerDisconnected ? 'bg-rose-500' : 'bg-emerald-500 shadow-[0_0_8px_#10b981]'}`} />
           </div>
           <div>
              <h3 className="font-black text-white tracking-tighter uppercase italic">
                {isPartnerDisconnected ? 'Thread Broken' : (partner.displayName || 'Stranger')}
              </h3>
              {partner.interests.length > 0 && (
                <div className="flex gap-1.5 mt-0.5 overflow-hidden">
                   {partner.interests.slice(0, 3).map(i => (
                     <span key={i} className="text-[9px] font-black uppercase tracking-widest text-indigo-400/70 border border-indigo-800/50 px-1.5 py-0.5 rounded">#{i}</span>
                   ))}
                </div>
              )}
           </div>
        </div>

        <div className="flex items-center gap-3">
          <button 
            onClick={onStop}
            className="p-3 text-slate-500 hover:text-rose-400 hover:bg-rose-500/10 rounded-2xl transition-all border-2 border-transparent hover:border-rose-900/30"
            title="Leave Loom"
          >
            <LogOut className="w-5 h-5" />
          </button>
          <button 
            onClick={onNext}
            className="group flex items-center gap-2 px-6 py-2.5 bg-indigo-600 hover:bg-indigo-500 text-white rounded-2xl text-xs font-black uppercase tracking-widest transition-all shadow-lg shadow-indigo-600/20 active:scale-95"
          >
            <span>Skip</span>
            <SkipForward className="w-4 h-4 group-hover:translate-x-1 transition-transform" />
          </button>
        </div>
      </div>

      {/* Loom Area (Messages) */}
      <div className="flex-1 overflow-y-auto p-6 space-y-6 scrollbar-none">
        <div className="flex justify-center my-6">
          <div className="bg-indigo-900/20 text-indigo-400 text-[10px] font-black uppercase tracking-[0.2em] px-4 py-2 rounded-2xl border border-dashed border-indigo-800/50">
            Connecting to the Loom... Thread Secure.
          </div>
        </div>

        {messages.map((msg) => {
           const isSystem = msg.sender === 'system';
           const isMe = msg.sender === 'me';

           if (isSystem) {
             return (
               <div key={msg.id} className="flex justify-center my-2">
                  <span className="text-[10px] font-bold text-slate-600 uppercase tracking-widest flex items-center gap-2">
                    <div className="h-[1px] w-8 bg-slate-800" />
                    {msg.text}
                    <div className="h-[1px] w-8 bg-slate-800" />
                  </span>
               </div>
             );
           }

           return (
            <div 
              key={msg.id} 
              className={`flex w-full animate-in fade-in slide-in-from-bottom-2 duration-300 ${isMe ? 'justify-end' : 'justify-start'}`}
            >
              <div 
                className={`group relative max-w-[85%] sm:max-w-[70%] px-5 py-4 rounded-patch shadow-xl transition-all hover:scale-[1.02] ${
                  isMe 
                    ? 'bg-indigo-600 text-white -rotate-1 rounded-tr-none border-b-4 border-r-4 border-indigo-800' 
                    : 'bg-denim-900 text-indigo-100 rotate-1 rounded-tl-none border-b-4 border-l-4 border-indigo-950'
                }`}
              >
                {/* Visual "Stitch" border inside bubble */}
                <div className="absolute inset-1 border border-dashed border-white/10 rounded-patch pointer-events-none" />

                <p className="relative z-10 font-medium leading-relaxed">{msg.text}</p>

                <div className={`text-[9px] font-black mt-2 uppercase tracking-widest opacity-40 ${isMe ? 'text-indigo-100' : 'text-indigo-400'}`}>
                  {new Date(msg.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
                </div>
              </div>
            </div>
           );
        })}

        {isPartnerDisconnected && (
          <div className="flex flex-col items-center justify-center gap-4 py-12">
             <div className="bg-rose-500/10 text-rose-400 p-4 rounded-patch border-2 border-dashed border-rose-900/30 flex flex-col items-center rotate-1">
                <p className="text-sm font-black uppercase tracking-widest mb-4">The yarn was cut.</p>
                <button 
                  onClick={onNext}
                  className="bg-rose-600 hover:bg-rose-500 text-white px-8 py-3 rounded-2xl font-black uppercase tracking-widest transition-all shadow-xl shadow-rose-600/20 active:scale-95"
                >
                  Find New Pattern
                </button>
             </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Bobbin Area (Input) */}
      <div className="p-6 bg-denim-950 border-t-2 border-dashed border-indigo-900/50">
        <form onSubmit={handleSend} className="relative flex items-center gap-3 max-w-4xl mx-auto">
          <input
            type="text"
            value={inputText}
            onChange={(e) => setInputText(e.target.value)}
            disabled={isPartnerDisconnected}
            placeholder={isPartnerDisconnected ? "Pattern finished..." : "Add your thread..."}
            className="w-full bg-denim-900 border-2 border-indigo-900/50 text-indigo-100 placeholder-indigo-900/60 rounded-2xl pl-6 pr-14 py-4 focus:border-indigo-500 outline-none disabled:opacity-50 transition-all font-medium"
          />
          <button
            type="submit"
            disabled={!inputText.trim() || isPartnerDisconnected}
            className="absolute right-2.5 p-3 bg-indigo-600 text-white rounded-xl hover:bg-indigo-500 disabled:opacity-0 disabled:scale-75 transition-all shadow-lg shadow-indigo-600/20 active:scale-90"
          >
            <Send className="w-5 h-5" />
          </button>
        </form>
      </div>
    </div>
  );
};

