      setMessages(prev => [
        ...prev,
        {
          id: uuidv4(),
          text: 'Stranger has left the chat.',
          sender: 'system',
          timestamp: Date.now()
        }
      ]);
    };

    const onStats = (data: { usersOnline: number }) => {
      setOnlineCount(data.usersOnline);
    };

    socket.on('connect', onConnect);
    socket.on('disconnect', onDisconnect);
    socket.on('partner_found', onPartnerFound);
    socket.on('message', onMessage);
    socket.on('partner_disconnected', onPartnerDisconnected);
    socket.on('stats', onStats);

    return () => {
      socket.off('connect', onConnect);
      socket.off('disconnect', onDisconnect);
      socket.off('partner_found', onPartnerFound);
      socket.off('message', onMessage);
      socket.off('partner_disconnected', onPartnerDisconnected);
      socket.off('stats', onStats);
    };
  }, []);

  const handleStartSearch = (prefs: UserPreferences) => {
    userPreferences.current = prefs;
    connectSocket();

    // If socket is already connected, emit immediately
    if (socket.connected) {
      socket.emit('find_partner', prefs);
      setAppState('searching');
    } else {
      // Wait for connection then emit
      setAppState('searching');
      socket.once('connect', () => {
        socket.emit('find_partner', prefs);
      });
    }
  };

  const handleSendMessage = (text: string) => {
    if (!text.trim()) return;

    socket.emit('send_message', { text });
    setMessages(prev => [
      ...prev,
      {
        id: uuidv4(),
        text: text,
        sender: 'me',
        timestamp: Date.now()
      }
    ]);
  };

  const handleNext = () => {
    socket.emit('skip_chat');
    setPartner(null);
    setMessages([]);
    setIsPartnerDisconnected(false);
    setAppState('searching');

    if (userPreferences.current) {
      socket.emit('find_partner', userPreferences.current);
    } else {
      setAppState('landing');
    }
  };

  const handleStop = () => {
    socket.emit('leave_chat');
    disconnectSocket();
    setAppState('landing');
    setPartner(null);
    setMessages([]);
    setIsPartnerDisconnected(false);
  };

  return (
    <div className="min-h-screen relative font-sans text-slate-100">

      {/* Background Ambience */}
      <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-[500px] h-[500px] bg-primary/20 rounded-full blur-[100px] animate-blob"></div>
        <div className="absolute top-[20%] right-[-10%] w-[400px] h-[400px] bg-secondary/20 rounded-full blur-[100px] animate-blob animation-delay-2000"></div>
        <div className="absolute bottom-[-10%] left-[20%] w-[600px] h-[600px] bg-accent/10 rounded-full blur-[120px] animate-blob animation-delay-4000"></div>
      </div>

      <div className="relative z-10 flex flex-col min-h-screen">
        <Header isConnected={isConnected} onlineCount={onlineCount} />

        <main className="flex-1 flex flex-col">
          {appState === 'landing' && (
            <Landing 
              onStart={handleStartSearch} 
              isConnecting={false} 
              isConnected={isConnected}
            />
          )}

          {appState === 'searching' && (
            <div className="flex-1 flex flex-col items-center justify-center p-4">
              <div className="relative mb-12">
                <div className="absolute inset-0 bg-primary/20 rounded-full blur-xl animate-pulse-glow"></div>
                <div className="relative w-24 h-24 glass-panel rounded-full flex items-center justify-center border border-primary/30">
                  <Loader2 className="w-10 h-10 text-primary animate-spin" />
                </div>
                {/* Radar Ripples */}
                <div className="absolute inset-0 rounded-full border border-primary/20 animate-ping opacity-20"></div>
              </div>

              <h2 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-primary to-secondary mb-3 animate-fade-in">
                Scanning Frequency...
              </h2>
              <p className="text-slate-400 max-w-md text-center animate-slide-up mb-6">
                Looking for someone interested in <span className="text-slate-200 font-medium">{userPreferences.current?.interests.join(', ') || 'anything'}</span>
              </p>

              {/* Testing Hint */}
              <div className="px-4 py-2 rounded-lg bg-blue-500/10 border border-blue-500/20 text-blue-300 text-xs font-mono animate-pulse">
                Tip: Open a new tab to test connection with yourself
              </div>

              <button 
                onClick={() => {
                    socket.emit('leave_chat');
                    setAppState('landing');
                }}
                className="mt-12 px-8 py-3 glass-panel hover:bg-white/10 rounded-full text-slate-300 transition-all text-sm font-medium tracking-wide uppercase hover:border-white/20"
              >
                Abort Scan
              </button>
            </div>
          )}

          {appState === 'chatting' && partner && (
            <ChatRoom
              partner={partner}
              messages={messages}
              onSendMessage={handleSendMessage}
              onNext={handleNext}
              onStop={handleStop}
              isPartnerDisconnected={isPartnerDisconnected}
            />
          )}
        </main>
      </div>
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { UserPreferences, Gender } from '../types';
import { Play, Plus, X, Globe2, Settings, Save, RotateCcw, Hash, WifiOff } from 'lucide-react';
import { SOCKET_URL, setStoredSocketUrl, resetStoredSocketUrl, DEMO_MODE } from '../constants';

interface LandingProps {
  onStart: (prefs: UserPreferences) => void;
  isConnecting: boolean;
  isConnected: boolean;
}

export const Landing: React.FC<LandingProps> = ({ onStart, isConnecting, isConnected }) => {
  const [displayName, setDisplayName] = useState('');
  const [age, setAge] = useState<string>('');
  const [gender, setGender] = useState<Gender>('Male');
  const [preferredGender, setPreferredGender] = useState<Gender | 'Any'>('Any');
  const [interestInput, setInterestInput] = useState('');
  const [interests, setInterests] = useState<string[]>([]);
  const [showSettings, setShowSettings] = useState(false);
  const [customUrl, setCustomUrl] = useState(SOCKET_URL);

  const handleAddInterest = (e?: React.FormEvent) => {
    e?.preventDefault();
    const trimmed = interestInput.trim();
    if (trimmed && !interests.includes(trimmed)) {
      setInterests([...interests, trimmed]);
      setInterestInput('');
    }
  };

  const removeInterest = (tag: string) => {
    setInterests(interests.filter(i => i !== tag));
  };

  const handleStart = () => {
    const ageNum = parseInt(age);
    if (!age || isNaN(ageNum) || ageNum < 18) {
      alert("Please enter a valid age (18+).");
      return;
    }
    onStart({
      displayName: displayName.trim() || 'Stranger',
      age: ageNum,
      gender,
      preferredGender,
      interests
    });
  };

  const saveSettings = () => {
    setStoredSocketUrl(customUrl);
    window.location.reload();
  };

  const resetSettings = () => {
    resetStoredSocketUrl();
    window.location.reload();
  };

  return (
    <div className="flex flex-col items-center justify-center min-h-screen pt-20 pb-10 px-4 sm:px-6">

      {/* Settings Toggle */}
      <button 
        onClick={() => setShowSettings(!showSettings)}
        className="absolute top-20 right-6 p-2.5 text-slate-400 hover:text-white hover:bg-white/5 rounded-full transition-all z-20"
      >
        <Settings className="w-5 h-5" />
      </button>

      {/* Settings Modal */}
      {showSettings && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-md p-6 animate-fade-in">
          <div className="glass-panel border-glass-border p-8 rounded-3xl w-full max-w-md shadow-2xl">
            <div className="flex justify-between items-center mb-6">
              <h3 className="text-xl font-bold text-white">System Config</h3>
              <button onClick={() => setShowSettings(false)} className="text-slate-500 hover:text-white transition-colors">
                <X className="w-6 h-6" />
              </button>
            </div>
            <div className="space-y-6">
              <div className="space-y-2">
                <label className="text-xs font-bold text-primary uppercase tracking-wider">Socket URL</label>
                <input 
                  type="text" 
                  value={customUrl}
                  onChange={(e) => setCustomUrl(e.target.value)}
                  className="w-full bg-black/40 border border-white/10 rounded-xl px-4 py-3 text-sm text-slate-200 focus:border-primary/50 outline-none transition-all"
                />
              </div>
              <div className="flex gap-4 pt-2">
                <button onClick={resetSettings} className="flex-1 py-3 px-4 rounded-xl border border-white/10 hover:bg-white/5 text-slate-400 font-medium transition-all flex items-center justify-center gap-2">
                  <RotateCcw className="w-4 h-4" /> Reset
                </button>
                <button onClick={saveSettings} className="flex-1 py-3 px-4 rounded-xl bg-primary hover:bg-primary/90 text-white font-bold shadow-lg shadow-primary/25 transition-all flex items-center justify-center gap-2">
                  <Save className="w-4 h-4" /> Save
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Main Card */}
      <div className="w-full max-w-5xl glass-panel rounded-[2rem] overflow-hidden shadow-2xl grid grid-cols-1 lg:grid-cols-5 min-h-[600px] border-glass-border">

        {/* Left Side: Branding */}
        <div className="lg:col-span-2 bg-gradient-to-br from-primary/10 via-background to-background p-10 flex flex-col justify-between relative overflow-hidden">
          <div className="absolute top-0 right-0 p-10 opacity-20">
            <Globe2 className="w-64 h-64 text-primary" />
          </div>

          <div className="relative z-10">
            <div className="inline-flex items-center gap-2 bg-white/5 border border-white/10 px-3 py-1 rounded-full text-xs font-medium text-primary mb-6">
              <span className="w-2 h-2 rounded-full bg-primary animate-pulse"></span>
              Global Network
            </div>
            <h2 className="text-4xl font-bold text-white leading-tight mb-4">
              Connect with <br/>
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-primary to-accent">Anyone, Anywhere.</span>
            </h2>
            <p className="text-slate-400 leading-relaxed">
              Experience the next generation of random chat. Filter by interests, find your tribe, and start the conversation.
            </p>
          </div>

          <div className="relative z-10 pt-10">
            <div className="flex -space-x-3 mb-4">
              {[1,2,3,4].map(i => (
                <div key={i} className="w-10 h-10 rounded-full border-2 border-background bg-slate-800 flex items-center justify-center text-xs font-bold text-slate-500">
                   ?
                </div>
              ))}
              <div className="w-10 h-10 rounded-full border-2 border-background bg-slate-800 flex items-center justify-center text-xs font-bold text-slate-300">
                +1k
              </div>
            </div>
            <p className="text-xs text-slate-500 font-medium uppercase tracking-widest">Users Online Now</p>
          </div>
        </div>

        {/* Right Side: Form */}
        <div className="lg:col-span-3 p-8 sm:p-12 bg-black/20 flex flex-col justify-center">

