import React, { useEffect, useState, useRef } from 'react';
import { Header } from './components/Header';
import { Landing } from './components/Landing';
import { ChatRoom } from './components/ChatRoom';
import { socket, connectSocket, disconnectSocket } from './services/socket';
import { UserPreferences, ChatState, Message, PartnerData } from './types';
import { Loader2, Radio } from 'lucide-react';
import { v4 as uuidv4 } from 'uuid';

function App() {
  const [appState, setAppState] = useState<ChatState>('landing');
  const [isConnected, setIsConnected] = useState(socket.connected);
  const [messages, setMessages] = useState<Message[]>([]);
  const [partner, setPartner] = useState<PartnerData | null>(null);
  const [onlineCount, setOnlineCount] = useState(0);
  const [isPartnerDisconnected, setIsPartnerDisconnected] = useState(false);
  const userPreferences = useRef<UserPreferences | null>(null);
  // Keep track of state for reconnection logic without triggering re-renders
  const appStateRef = useRef<ChatState>('landing');

  useEffect(() => {
    appStateRef.current = appState;
  }, [appState]);

  useEffect(() => {
    // Socket Event Listeners
    const onConnect = () => {
      setIsConnected(true);
      console.log('Connected to server');

      // If we were searching when disconnected, restart the search automatically
      if (appStateRef.current === 'searching' && userPreferences.current) {
        console.log('Restoring search session...');
        socket.emit('find_partner', userPreferences.current);
      }
    };

    const onDisconnect = () => {
      setIsConnected(false);
      console.log('Disconnected from server');
    };

    const onPartnerFound = (data: PartnerData) => {
      setPartner(data);
      setAppState('chatting');
      setMessages([]);
      setIsPartnerDisconnected(false);
    };

    const onMessage = (data: { text: string, senderId: string }) => {
      setMessages(prev => [
        ...prev, 
        { 
          id: uuidv4(), 
          text: data.text, 
          sender: 'stranger', 
          timestamp: Date.now() 
        }
      ]);
    };

    const onPartnerDisconnected = () => {
      setIsPartnerDisconnected(true);
      setMessages(prev => [
        ...prev,
        {
          id: uuidv4(),
          text: 'Stranger has left the chat.',
          sender: 'system',
          timestamp: Date.now()
        }
      ]);
    };

    const onStats = (data: { usersOnline: number }) => {
      setOnlineCount(data.usersOnline);
    };

    socket.on('connect', onConnect);
    socket.on('disconnect', onDisconnect);
    socket.on('partner_found', onPartnerFound);
    socket.on('message', onMessage);
    socket.on('partner_disconnected', onPartnerDisconnected);
    socket.on('stats', onStats);

    return () => {
      socket.off('connect', onConnect);
      socket.off('disconnect', onDisconnect);
      socket.off('partner_found', onPartnerFound);
      socket.off('message', onMessage);
      socket.off('partner_disconnected', onPartnerDisconnected);
      socket.off('stats', onStats);
    };
  }, []);

  const handleStartSearch = (prefs: UserPreferences) => {
    userPreferences.current = prefs;
    connectSocket();

    // If socket is already connected, emit immediately
    if (socket.connected) {
      socket.emit('find_partner', prefs);
      setAppState('searching');
    } else {
      // Wait for connection then emit
      setAppState('searching');
      socket.once('connect', () => {
        socket.emit('find_partner', prefs);
      });
    }
  };

  const handleSendMessage = (text: string) => {
    if (!text.trim()) return;

    socket.emit('send_message', { text });
    setMessages(prev => [
      ...prev,
      {
        id: uuidv4(),
        text: text,
        sender: 'me',
        timestamp: Date.now()
      }
    ]);
  };

  const handleNext = () => {
    socket.emit('skip_chat');
    setPartner(null);
    setMessages([]);
    setIsPartnerDisconnected(false);
    setAppState('searching');

    if (userPreferences.current) {
      socket.emit('find_partner', userPreferences.current);
    } else {
      setAppState('landing');
    }
  };

  const handleStop = () => {
    socket.emit('leave_chat');
    disconnectSocket();
    setAppState('landing');
    setPartner(null);
    setMessages([]);
    setIsPartnerDisconnected(false);
  };

  return (
    <div className="min-h-screen relative font-sans text-slate-100">

      {/* Background Ambience */}
      <div className="fixed inset-0 pointer-events-none z-0 overflow-hidden">
        <div className="absolute top-[-10%] left-[-10%] w-[500px] h-[500px] bg-primary/20 rounded-full blur-[100px] animate-blob"></div>
        <div className="absolute top-[20%] right-[-10%] w-[400px] h-[400px] bg-secondary/20 rounded-full blur-[100px] animate-blob animation-delay-2000"></div>
        <div className="absolute bottom-[-10%] left-[20%] w-[600px] h-[600px] bg-accent/10 rounded-full blur-[120px] animate-blob animation-delay-4000"></div>
      </div>

      <div className="relative z-10 flex flex-col min-h-screen">
        <Header isConnected={isConnected} onlineCount={onlineCount} />

        <main className="flex-1 flex flex-col">
          {appState === 'landing' && (
            <Landing 
              onStart={handleStartSearch} 
              isConnecting={false} 
              isConnected={isConnected}
            />
          )}

          {appState === 'searching' && (
            <div className="flex-1 flex flex-col items-center justify-center p-4">
              <div className="relative mb-12">
                <div className="absolute inset-0 bg-primary/20 rounded-full blur-xl animate-pulse-glow"></div>
                <div className="relative w-24 h-24 glass-panel rounded-full flex items-center justify-center border border-primary/30">
                  <Loader2 className="w-10 h-10 text-primary animate-spin" />
                </div>
                {/* Radar Ripples */}
                <div className="absolute inset-0 rounded-full border border-primary/20 animate-ping opacity-20"></div>
              </div>

              <h2 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-primary to-secondary mb-3 animate-fade-in">
                Scanning Frequency...
              </h2>
              <p className="text-slate-400 max-w-md text-center animate-slide-up mb-6">
                Looking for someone interested in <span className="text-slate-200 font-medium">{userPreferences.current?.interests.join(', ') || 'anything'}</span>
              </p>

              {/* Testing Hint */}
              <div className="px-4 py-2 rounded-lg bg-blue-500/10 border border-blue-500/20 text-blue-300 text-xs font-mono animate-pulse">
                Tip: Open a new tab to test connection with yourself
              </div>

              <button 
                onClick={() => {
                    socket.emit('leave_chat');
                    setAppState('landing');
                }}
                className="mt-12 px-8 py-3 glass-panel hover:bg-white/10 rounded-full text-slate-300 transition-all text-sm font-medium tracking-wide uppercase hover:border-white/20"
              >
                Abort Scan
              </button>
            </div>
          )}

          {appState === 'chatting' && partner && (
            <ChatRoom
              partner={partner}
              messages={messages}
              onSendMessage={handleSendMessage}
              onNext={handleNext}
              onStop={handleStop}
              isPartnerDisconnected={isPartnerDisconnected}
            />
          )}
        </main>
      </div>
    </div>
  );
}

export default App;

import { io, Socket } from 'socket.io-client';
import { SOCKET_URL, DEMO_MODE } from '../constants';
import { v4 as uuidv4 } from 'uuid';

// Mock Socket for Demo Mode
class MockSocket {
  connected = false;
  private listeners: Map<string, Function[]> = new Map();
  private partner: any = null;

  on(event: string, callback: Function) {
    if (!this.listeners.has(event)) {
      this.listeners.set(event, []);
    }
    this.listeners.get(event)?.push(callback);
    return this;
  }

  off(event: string, callback: Function) {
    const callbacks = this.listeners.get(event);
    if (callbacks) {
      this.listeners.set(event, callbacks.filter(cb => cb !== callback));
    }
    return this;
  }

  emit(event: string, data: any) {
    console.log(`[MockSocket] Emitting: ${event}`, data);

    if (event === 'find_partner') {
      setTimeout(() => {
        const interests = data.interests || [];
        const commonInterest = interests.length > 0 
          ? interests[Math.floor(Math.random() * interests.length)] 
          : 'Random Chat';

        this.partner = {
          socketId: 'mock-partner-' + uuidv4(),
          displayName: 'Stranger',
          interests: interests.length > 0 ? [commonInterest, 'Tech', 'Music'] : [],
          gender: 'Anonymous'
        };

        this.trigger('partner_found', this.partner);
      }, 1500 + Math.random() * 1000); // Simulate network delay
    }

    if (event === 'send_message') {
      // Echo random reply
      setTimeout(() => {
        if (!this.connected || !this.partner) return;

        const replies = [
          "That's interesting!",
          "Tell me more about that.",
          "I totally agree.",
          "Haha, really?",
          "I've never thought about it that way.",
          `Do you like ${this.partner.interests[0] || 'chatting'}?`,
          "I'm actually a demo bot living in your browser 🤖",
          "Cool!",
        ];
        const randomReply = replies[Math.floor(Math.random() * replies.length)];

        this.trigger('message', {
          text: randomReply,
          senderId: this.partner.socketId
        });
      }, 1000 + Math.random() * 2000);
    }

    if (event === 'leave_chat' || event === 'skip_chat') {
      this.partner = null;
      this.trigger('partner_disconnected');
    }
  }

  connect() {
    setTimeout(() => {
        this.connected = true;
        this.trigger('connect');
        this.trigger('stats', { usersOnline: Math.floor(Math.random() * 500) + 1000 });
    }, 100);
  }

  disconnect() {
    this.connected = false;
    this.trigger('disconnect');
  }

  private trigger(event: string, data?: any) {
    const callbacks = this.listeners.get(event);
    if (callbacks) {
      callbacks.forEach(cb => cb(data));
    }
  }
}

